    let name = driver.device_name();
    if let Some(irq) = irq {
        INTERRUPT_MAP.write().insert(irq, driver.clone());
    }

    DRIVERS.write().insert(name.clone(), driver.clone());

    devfs::add_device(name, driver);
}

