impl Arch {
    pub fn try_uptime() -> Option<Duration> {
        let freq = *STABLE_COUNTER_FREQ_HZ.try_get()?;
        if freq == 0 {
            return None;
        }
        Some(Duration::from_micros(csr::rdtime().saturating_mul(1_000_000) / freq))
    }
}

