pub fn getpgid(pid: usize) -> SyscallRet {
    let pid = pid as i32;
    if pid == 0 {
        Ok(current::pcb().pgid() as usize)
    } else {
        let tcb = crate::kernel::task::manager::get(pid).ok_or(Errno::ESRCH)?;
        Ok(tcb.parent().pgid() as usize)
    }
}

