    let pid = pid as Tid;
    if pid == 0 {
        Ok(current::pcb().sid() as usize)
    } else {
        let pcb = find_process(pid).ok_or(Errno::ESRCH)?;
        Ok(pcb.sid() as usize)
    }
}

