struct HeapAllocator {
    mutex: Mutex<()>,
}

impl HeapAllocator {
    pub const fn new() -> Self {
        HeapAllocator { mutex: Mutex::new(()) }
    }

    pub fn init(&self, heap_start: usize, heap_size: usize) {
