pub fn statfs(sno: u32) -> SysResult<Statfs> {
    let vfs = vfs();
    let readonly = vfs.is_superblock_readonly(sno)?;
    let mut statfs = vfs.get_superblock(sno)?.statfs()?;

    if readonly {
        statfs.f_flag |= StatfsFlags::ST_RDONLY.bits();
    } else {
        statfs.f_flag &= !StatfsFlags::ST_RDONLY.bits();
    }
    Ok(statfs)
}

